// Track which tasks have already shown their notification this session
const _snShownTasks = new Set()

function showSupportNotif(taskIdx) {
	// Only show once per task — no repeat on re-check
	if (_snShownTasks.has(taskIdx)) return
	_snShownTasks.add(taskIdx)

	const lang = typeof LANG !== 'undefined' && SUPPORT_MSGS[LANG] ? LANG : 'kk'
	const msgs = SUPPORT_MSGS[lang]
	// Fixed: task 0 → msg[0], task 1 → msg[1], etc.
	const msg = msgs[taskIdx % msgs.length]

	const existing = document.getElementById('support-notif')
	if (existing) {
		existing.remove()
		clearTimeout(window._snTimer)
		clearTimeout(window._snHideTimer)
	}

	const notif = document.createElement('div')
	notif.id = 'support-notif'

	const iconEl = document.createElement('div')
	iconEl.className = 'sn-icon'
	const emojiMatch = msg.match(
		/^(\p{Emoji_Presentation}|\p{Extended_Pictographic})+/u
	)
	iconEl.textContent = emojiMatch ? emojiMatch[0] : '🌸'

	const textEl = document.createElement('div')
	textEl.className = 'sn-text'
	textEl.textContent = msg.replace(
		/^(\p{Emoji_Presentation}|\p{Extended_Pictographic})+\s*/u,
		''
	)

	const bar = document.createElement('div')
	bar.className = 'sn-bar'
	bar.style.width = '100%'

	notif.appendChild(iconEl)
	notif.appendChild(textEl)
	notif.appendChild(bar)
	document.body.appendChild(notif)

	const DURATION = 3800
	requestAnimationFrame(() => {
		requestAnimationFrame(() => {
			bar.style.transition = 'width ' + DURATION + 'ms linear'
			bar.style.width = '0%'
		})
	})

	window._snHideTimer = setTimeout(() => {
		notif.classList.add('hiding')
		window._snTimer = setTimeout(() => {
			if (notif.parentNode) notif.remove()
		}, 340)
	}, DURATION)
}

function el(tag, attrs, ...children) {
	const e = document.createElement(tag)
	if (attrs)
		for (const [k, v] of Object.entries(attrs)) {
			if (k === 'style' && typeof v === 'object') Object.assign(e.style, v)
			else if (k.startsWith('on'))
				e.addEventListener(k.slice(2).toLowerCase(), v)
			else if (k === 'className') e.className = v
			else e.setAttribute(k, v)
		}
	for (const c of children) {
		if (c === null || c === undefined) continue
		if (typeof c === 'string') e.appendChild(document.createTextNode(c))
		else if (c instanceof Node) e.appendChild(c)
	}
	return e
}
function div(a, ...c) {
	return el('div', a, ...c)
}
function span(a, ...c) {
	return el('span', a, ...c)
}
function btn(a, ...c) {
	return el('button', a, ...c)
}
function inp(a) {
	return el('input', a)
}
function sel(a, opts, val) {
	const s = el('select', a)
	for (const o of opts) {
		const opt = el('option', { value: o }, o)
		if (o === val) opt.selected = true
		s.appendChild(opt)
	}
	return s
}
function field(labelTxt, type, id, placeholder) {
	const wrap = div({ style: { marginBottom: '14px' } })
	const lbl = el('label', { className: 'lbl', for: id }, labelTxt)
	const input = inp({
		type: type || 'text',
		id,
		placeholder: placeholder || '',
		className: 'inp',
	})
	if (type === 'password') {
		const row = div({ style: { position: 'relative' } })
		const eye = span(
			{
				style: {
					position: 'absolute',
					right: '12px',
					top: '50%',
					transform: 'translateY(-50%)',
					cursor: 'pointer',
					fontSize: '16px',
					color: 'var(--text3)',
				},
			},
			'👁'
		)
		let shown = false
		eye.onclick = () => {
			shown = !shown
			input.type = shown ? 'text' : 'password'
			eye.textContent = shown ? '🙈' : '👁'
		}
		row.appendChild(input)
		row.appendChild(eye)
		wrap.appendChild(lbl)
		wrap.appendChild(row)
	} else {
		wrap.appendChild(lbl)
		wrap.appendChild(input)
	}
	const errEl = div({ className: 'errtxt', style: { display: 'none' } })
	wrap.appendChild(errEl)
	return { wrap, input, errEl }
}
function showErr(f, msg) {
	f.input.classList.add('err')
	f.errEl.textContent = msg
	f.errEl.style.display = 'block'
}
function clearErr(f) {
	f.input.classList.remove('err')
	f.errEl.style.display = 'none'
}
function langSwitcher(onchange) {
	const wrap = div({
		style: { display: 'flex', gap: '6px', alignItems: 'center' },
	})
	;['kk', 'ru', 'en'].forEach(lang => {
		const b = btn(
			{ className: 'lang-btn' + (LANG === lang ? ' active' : '') },
			T[lang]['lang' + lang.charAt(0).toUpperCase() + lang.slice(1)]
		)
		b.onclick = () => {
			LANG = lang
			if (onchange) onchange(lang)
		}
		wrap.appendChild(b)
	})
	// ── Accessibility (screen reader) toggle button ──────────────────────────────
	const a11yBtn = btn({
		className: 'lang-btn' + (window._a11yMode ? ' active' : ''),
	})
	a11yBtn.title = 'Режим для слабовидящих / Нашар көретіндерге арналған режим'
	a11yBtn.innerHTML = '👁'
	a11yBtn.style.cssText += ';min-width:36px;padding:4px 8px;font-size:16px;'
	a11yBtn.onclick = () => {
		window._a11yMode = !window._a11yMode
		a11yBtn.className = 'lang-btn' + (window._a11yMode ? ' active' : '')
		_a11yApply(window._a11yMode)
		if (window._a11yMode) {
			const msg =
				LANG === 'kk'
					? 'Дауыстық режим қосылды. Кез келген мәтінді оқу үшін оны басыңыз.'
					: LANG === 'en'
					? 'Voice mode enabled. Click any text to hear it.'
					: 'Голосовой режим включён. Нажмите на любой текст, чтобы услышать его.'
			_ttsSpeak(msg)
		} else {
			window.speechSynthesis && window.speechSynthesis.cancel()
		}
		try {
			localStorage.setItem('qolda_a11y', window._a11yMode ? '1' : '0')
		} catch (e) {}
	}
	wrap.appendChild(a11yBtn)
	return wrap
}

// ── Screen reader engine ──────────────────────────────────────────────────────
window._a11yMode = (() => {
	try {
		return localStorage.getItem('qolda_a11y') === '1'
	} catch (e) {
		return false
	}
})()

function _ttsSpeak(text) {
	if (!window.speechSynthesis) return
	window.speechSynthesis.cancel()
	const clean = text
		.replace(/[#*_~`<>]/g, '')
		.replace(/\s+/g, ' ')
		.trim()
	if (!clean) return
	const utt = new SpeechSynthesisUtterance(clean)
	// Language mapping
	utt.lang = LANG === 'kk' ? 'kk-KZ' : LANG === 'en' ? 'en-US' : 'ru-RU'
	utt.rate = 0.92
	utt.pitch = 1
	utt.volume = 1
	// Try to pick a matching voice
	const voices = window.speechSynthesis.getVoices()
	const langCode = utt.lang.slice(0, 2)
	const match = voices.find(v => v.lang.startsWith(langCode))
	if (match) utt.voice = match
	window.speechSynthesis.speak(utt)
}

// Inject a11y styles + click-to-speak handler
function _a11yApply(on) {
	// Styles
	let styleEl = document.getElementById('_a11yStyle')
	if (!styleEl) {
		styleEl = document.createElement('style')
		styleEl.id = '_a11yStyle'
		document.head.appendChild(styleEl)
	}
	styleEl.textContent = on
		? `
    body { font-size: 118% !important; }
    .card, .tab-btn, .btn-primary, .btn-outline, .lang-btn,
    button, input, select, a, label, p, h1, h2, h3, li, span, div[role] {
      cursor: pointer !important;
    }
    ._a11y-hover {
      outline: 2.5px solid var(--g1) !important;
      outline-offset: 2px !important;
      background: rgba(212,104,122,.08) !important;
      border-radius: 6px !important;
      transition: outline .12s, background .12s !important;
    }
    #_a11yBar {
      position: fixed; bottom: 80px; left: 50%; transform: translateX(-50%);
      background: #1a1a2e; color: #fff; border-radius: 16px;
      padding: 10px 20px; font-size: 13px; font-weight: 600;
      z-index: 9999; max-width: 88vw; text-align: center;
      box-shadow: 0 8px 32px rgba(0,0,0,.45); pointer-events: none;
      opacity: 0; transition: opacity .25s;
      display: flex; align-items: center; gap: 10px;
    }
    #_a11yBar.visible { opacity: 1; }
    #_a11yBar .a11y-icon { font-size: 18px; flex-shrink: 0; }
    #_a11yBar .a11y-stop {
      pointer-events: auto; cursor: pointer;
      background: rgba(255,255,255,.18); border: none; color: #fff;
      border-radius: 8px; padding: 3px 10px; font-size: 12px; margin-left: 6px;
    }
  `
		: ''

	// Status bar
	let bar = document.getElementById('_a11yBar')
	if (on && !bar) {
		bar = document.createElement('div')
		bar.id = '_a11yBar'
		bar.innerHTML = `<span class="a11y-icon">🔊</span><span id="_a11yBarText"></span><button class="a11y-stop" onclick="window.speechSynthesis&&window.speechSynthesis.cancel();document.getElementById('_a11yBar').classList.remove('visible')">■ Стоп</button>`
		document.body.appendChild(bar)
	} else if (!on && bar) {
		bar.remove()
	}

	// Event listeners
	if (on) {
		document.addEventListener('click', _a11yClickHandler, true)
		document.addEventListener('mouseover', _a11yHoverHandler, true)
		document.addEventListener('mouseout', _a11yOutHandler, true)
	} else {
		document.removeEventListener('click', _a11yClickHandler, true)
		document.removeEventListener('mouseover', _a11yHoverHandler, true)
		document.removeEventListener('mouseout', _a11yOutHandler, true)
	}
}

function _a11yGetText(el) {
	// Skip the accessibility button itself and stop button
	if (el.id === '_a11yBar' || (el.closest && el.closest('#_a11yBar'))) return ''
	const tag = (el.tagName || '').toLowerCase()
	if (tag === 'input')
		return el.placeholder || el.value || el.labels?.[0]?.textContent || ''
	if (tag === 'select') return el.options[el.selectedIndex]?.text || ''
	if (tag === 'img') return el.alt || ''
	const txt = (el.innerText || el.textContent || '').trim()
	return txt.slice(0, 300)
}

function _a11yClickHandler(e) {
	if (!window._a11yMode) return
	const txt = _a11yGetText(e.target)
	if (!txt || txt.length < 2) return
	_ttsSpeak(txt)
	const bar = document.getElementById('_a11yBar')
	const barTxt = document.getElementById('_a11yBarText')
	if (bar && barTxt) {
		barTxt.textContent = txt.slice(0, 80) + (txt.length > 80 ? '…' : '')
		bar.classList.add('visible')
		clearTimeout(window._a11yBarTimer)
		window._a11yBarTimer = setTimeout(
			() => bar.classList.remove('visible'),
			4000
		)
	}
}

function _a11yHoverHandler(e) {
	if (!window._a11yMode) return
	if (e.target.closest && e.target.closest('#_a11yBar')) return
	e.target.classList && e.target.classList.add('_a11y-hover')
}
function _a11yOutHandler(e) {
	e.target.classList && e.target.classList.remove('_a11y-hover')
}

// Apply on load if previously enabled
if (window._a11yMode) {
	if (document.readyState === 'loading') {
		document.addEventListener('DOMContentLoaded', () => _a11yApply(true))
	} else {
		_a11yApply(true)
	}
}

function simpleMarkdown(text) {
	if (!text) return ''
	return text
		.replace(/&/g, '&amp;')
		.replace(/</g, '&lt;')
		.replace(/>/g, '&gt;')
		.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
		.replace(
			/## (.*?)(\n|$)/g,
			'<div style="font-weight:800;font-size:15px;margin:10px 0 4px;color:var(--g1)">$1</div>'
		)
		.replace(
			/- (.*?)(\n|$)/g,
			'<div style="display:flex;gap:6px;margin:2px 0"><span style="color:var(--g2)">•</span><span>$1</span></div>'
		)
		.replace(/\n/g, '<br>')
}

