	function renderPlan() {
		const p = getPlan()
		const done = (u.planDone || []).length
		const pct = Math.round((done / p.length) * 100)
		const wrap = div({})

		// Plan items
		const c = div({ className: 'card' })
		c.appendChild(
			div(
				{
					style: {
						fontFamily: "'Inter',sans-serif",
						fontWeight: '900',
						fontSize: '18px',
						marginBottom: '6px',
					},
				},
				LANG === 'kk'
					? '📋 Көмек алуды рәсімдеудің қадамдық жоспары'
					: LANG === 'en'
					? '📋 Step-by-step plan to receive support'
					: '📋 Пошаговый план оформления помощи'
			)
		)
		c.appendChild(
			div(
				{
					style: {
						fontSize: '13px',
						color: 'var(--text3)',
						marginBottom: '18px',
					},
				},
				LANG === 'kk'
					? 'Осы қадамдарды орындау арқылы балаңызға мүгедектік рәсімдеп, жәрдемақылар мен қажетті қызметтерді ала аласыз.'
					: LANG === 'en'
					? 'Follow these steps to apply for disability status, benefits, and essential services for your child.'
					: 'Следуйте этим шагам, чтобы оформить инвалидность, пособия и необходимые услуги для ребёнка.'
			)
		)
		p.forEach((item, i) => {
			const isDone = (u.planDone || []).includes(i)
			const wrapper = div({ style: { marginBottom: '10px' } })
			let expandOpen = false
			// Build detail box first
			let detailBox = null
			if (item.steps && item.steps.length > 0) {
				detailBox = div({
					style: {
						display: 'none',
						borderRadius: '0 0 14px 14px',
						background: 'linear-gradient(135deg,#fdf6ff,#f0f9f6)',
						border: '1.5px solid var(--g2)',
						borderTop: 'none',
						padding: '16px 18px',
					},
				})
				item.steps.forEach((step, si) => {
					const stepWrap = div({
						style: { marginBottom: si < item.steps.length - 1 ? '14px' : '0' },
					})
					const qEl = div(
						{
							style: {
								fontFamily: "'Inter',sans-serif",
								fontWeight: '800',
								fontSize: '13px',
								color: 'var(--g1)',
								marginBottom: '5px',
							},
						},
						step.q
					)
					const aLines = step.a.split('\n')
					const aWrap = div({
						style: { display: 'flex', flexDirection: 'column', gap: '3px' },
					})
					aLines.forEach(line => {
						const lineEl = div({
							style: {
								fontSize: '12.5px',
								color: 'var(--text2)',
								lineHeight: '1.6',
								paddingLeft: line.startsWith('\u2022') ? '8px' : '0',
							},
						})
						if (step.link) {
							const anchor = document.createElement('a')
							anchor.href = step.link
							anchor.target = '_blank'
							anchor.rel = 'noopener noreferrer'
							anchor.textContent = line
							anchor.style.cssText = 'color:#2563eb;text-decoration:underline;cursor:pointer;font-weight:600;transition:color .15s,opacity .15s;'
							anchor.addEventListener('mouseenter', function() { this.style.color = '#1d4ed8'; this.style.opacity = '0.85'; })
							anchor.addEventListener('mouseleave', function() { this.style.color = '#2563eb'; this.style.opacity = '1'; })
							lineEl.appendChild(anchor)
						} else {
							lineEl.textContent = line
						}
						aWrap.appendChild(lineEl)
					})
					stepWrap.appendChild(qEl)
					stepWrap.appendChild(aWrap)
					detailBox.appendChild(stepWrap)
				})
			}
			// Main row
			const row = div({
				style: {
					display: 'flex',
					alignItems: 'center',
					gap: '14px',
					padding: '14px 16px',
					borderRadius: expandOpen ? '14px 14px 0 0' : '14px',
					border: '1.5px solid ' + (isDone ? 'var(--g2)' : 'var(--border)'),
					cursor: 'pointer',
					background: isDone ? 'var(--g4)' : '#fff',
					transition: 'all .2s',
				},
			})
			row.appendChild(
				div(
					{
						style: {
							width: '42px',
							height: '42px',
							borderRadius: '12px',
							background: 'linear-gradient(135deg,var(--g4),var(--g6))',
							display: 'flex',
							alignItems: 'center',
							justifyContent: 'center',
							fontSize: '19px',
							flexShrink: '0',
						},
					},
					item.icon
				)
			)
			const info = div({ style: { flex: '1' } })
			const titleEl = div(
				{
					style: {
						fontSize: '14px',
						fontWeight: '700',
						textDecoration: isDone ? 'line-through' : 'none',
						color: isDone ? 'var(--text3)' : 'var(--text)',
					},
				},
				item.title
			)
			info.appendChild(titleEl)
			if (item.desc)
				info.appendChild(
					div(
						{
							style: {
								fontSize: '12px',
								color: 'var(--text3)',
								marginTop: '2px',
							},
						},
						item.desc
					)
				)
			row.appendChild(info)
			// Check circle only (no arrow)
			const checkCircle = div(
				{
					style: {
						width: '30px',
						height: '30px',
						borderRadius: '50%',
						border: '2px solid ' + (isDone ? 'var(--g1)' : 'var(--border)'),
						background: isDone ? 'var(--g1)' : '#fff',
						display: 'flex',
						alignItems: 'center',
						justifyContent: 'center',
						fontSize: '13px',
						color: '#fff',
						fontWeight: '800',
						flexShrink: '0',
						transition: 'all .22s',
						boxShadow: isDone ? '0 2px 10px rgba(212,104,122,.35)' : 'none',
					},
				},
				isDone ? '✓' : ''
			)
			checkCircle.onclick = e => {
				e.stopPropagation()
				togglePlanItem(i)
			}
			row.appendChild(checkCircle)
			// Row click = expand/collapse
			if (detailBox) {
				row.onclick = () => {
					expandOpen = !expandOpen
					detailBox.style.display = expandOpen ? 'block' : 'none'
					row.style.borderRadius = expandOpen ? '14px 14px 0 0' : '14px'
					row.style.borderColor = expandOpen
						? 'var(--g2)'
						: isDone
						? 'var(--g2)'
						: 'var(--border)'
				}
			} else {
				row.onclick = () => togglePlanItem(i)
			}
			wrapper.appendChild(row)
			if (detailBox) wrapper.appendChild(detailBox)
			c.appendChild(wrapper)
		})
		wrap.appendChild(c)
		content.appendChild(wrap)
	}

