		const isDisability =
			u.diag === disabilityDiagValues[LANG] ||
			u.diag === 'Мүгедектік' ||
			u.diag === 'Инвалидность' ||
			u.diag === 'Disability'
		let benefitKey = null
		if (isDisability && u.disabilityGroup) {
			const g = u.disabilityGroup
			if (g === 'I группа' || g === 'I топ' || g === 'Group I')
				benefitKey = 'disability_group1'
			else if (g === 'II группа' || g === 'II топ' || g === 'Group II')
				benefitKey = 'disability_group2'
			else if (g === 'III группа' || g === 'III топ' || g === 'Group III')
				benefitKey = 'disability_group3'
		}

